import{SceneManager}from"./SceneManager.js";import{CombatScene}from"../scenes/CombatScene.js";class Game{constructor(e){this.canvas=document.getElementById(e),this.ctx=this.canvas.getContext("2d"),this.sceneManager=new SceneManager(this)}start(){this.sceneManager.changeScene(CombatScene),this.gameLoop()}gameLoop(){this.update(),this.render(),requestAnimationFrame(()=>this.gameLoop())}update(){this.sceneManager.currentScene&&this.sceneManager.currentScene.update()}render(){this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height),this.sceneManager.currentScene&&this.sceneManager.currentScene.render(this.ctx)}}export{Game};